const hits = $json.hits || [];
const IDEA_SIGNALS = /\b(app|tool|platform|api|saas|marketplace|service|software|product|automat|dashboard|monitor|analytic|generat|assist|integrat|workflow|schedule|track|manage|build|launch)\b/i;
const REJECT = /\b(news|article|book|podcast|video|tweet|thread|death|disaster|war|politic|sport|music|movie|game|photo|opinion)\b/i;

const results = [];
for (const hit of hits) {
  const text = (hit.title || '') + ' ' + (hit.story_text || '');
  if (!IDEA_SIGNALS.test(text) || REJECT.test(text)) continue;
  if ((hit.points || 0) < 10) continue;
  if ((hit.title || '').length < 20) continue;
  results.push({
    raw_title: hit.title,
    raw_content: (hit.title + '. ' + (hit.story_text || '')).substring(0, 800),
    source_url: hit.url || ('https://news.ycombinator.com/item?id=' + hit.objectID),
    source_platform: 'hackernews',
    upvotes: hit.points || 0,
    comment_count: hit.num_comments || 0,
    scraped_at: new Date().toISOString()
  });
}

if (results.length === 0) return [{ json: { _skip: true } }];
return results.map(r => ({ json: r }));

const xml = $json.data || '';
const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
while ((match = itemRegex.exec(xml)) !== null) {
  const seg = match[1];
  const getTag = function(tag) {
    const r = new RegExp('<' + tag + '>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/' + tag + '>');
    const m = r.exec(seg);
    return m ? m[1].trim() : '';
  };
  const title = getTag('title');
  const desc = getTag('description').replace(/<[^>]+>/g, '').substring(0, 600);
  const link = getTag('link');
  if (!title || !link || title.length < 15) continue;
  items.push({
    raw_title: title,
    raw_content: (title + '. ' + desc).substring(0, 800),
    source_url: link,
    source_platform: 'producthunt',
    upvotes: 0,
    comment_count: 0,
    scraped_at: new Date().toISOString()
  });
}
if (items.length === 0) return [{ json: { _skip: true } }];
return items.map(i => ({ json: i }));

const IDEA_SIGNALS = /\b(app|tool|platform|api|saas|marketplace|service|software|product|automat|dashboard|monitor|analytic|generat|assist|integrat|workflow|schedule|track|manage)\b/i;
const REJECT = /\b(opinion|showhn|ask hn|news|blog|article|tutorial|course|book|podcast|video|thread|death|disaster|war|politic|sport|music|movie|game|photo)\b/i;

const seen = new Set();
const filtered = [];

for (const item of $input.all()) {
  const d = item.json;
  if (d._skip) continue;
  if (!d.source_url) continue;
  if (seen.has(d.source_url)) continue;
  seen.add(d.source_url);
  const text = (d.raw_title || '') + ' ' + (d.raw_content || '');
  if (!IDEA_SIGNALS.test(text)) continue;
  if (REJECT.test(text)) continue;
  if ((d.raw_title || '').length < 20) continue;
  filtered.push(item);
}

if (filtered.length === 0) return [{ json: { _skip: true } }];
return filtered;

const claudeResp = $json;
const orig = $('Split In Batches').item.json;

let text = '';
try {
  text = claudeResp.content[0].text;
} catch(e) {
  console.log('Claude resp error:', JSON.stringify(claudeResp).substring(0, 200));
  return [{ json: { _skip: true } }];
}

// Handle explicit reject
if (text.includes('"reject": true') || text.includes('"reject":true')) {
  return [{ json: { _skip: true } }];
}

let parsed;
try {
  const m = text.match(/```json[\s\S]*?```/) ?
    text.match(/```json\s*([\s\S]*?)\s*```/) :
    text.match(/(\{[\s\S]*\})/);
  if (!m) throw new Error('no json');
  parsed = JSON.parse(m[1]);
} catch(e) {
  console.log('JSON parse fail:', text.substring(0, 300));
  return [{ json: { _skip: true } }];
}

if (parsed.reject) return [{ json: { _skip: true } }];
if (!parsed.title || !parsed.summary) return [{ json: { _skip: true } }];
if ((parsed.ai_score || 0) < 60) return [{ json: { _skip: true } }];

return [{
  json: {
    title: (parsed.title || '').substring(0, 200),
    summary: parsed.summary || '',
    pain_points: Array.isArray(parsed.pain_points) ? parsed.pain_points.slice(0, 5) : [],
    target_customers: Array.isArray(parsed.target_customers) ? parsed.target_customers.slice(0, 4) : [],
    monetization_strategies: Array.isArray(parsed.monetization_strategies) ? parsed.monetization_strategies.slice(0, 4) : [],
    tech_stack_suggestions: Array.isArray(parsed.tech_stack_suggestions) ? parsed.tech_stack_suggestions.slice(0, 5) : [],
    tags: Array.isArray(parsed.tags) ? parsed.tags.slice(0, 5) : [],
    competitive_edge: parsed.competitive_edge || null,
    why_now: parsed.why_now || null,
    market_gap: parsed.market_gap || null,
    ai_score: Math.min(100, Math.max(0, Number(parsed.ai_score) || 60)),
    source_url: orig.source_url,
    source_platform: orig.source_platform,
    upvotes: orig.upvotes || 0,
    comment_count: orig.comment_count || 0,
    scraped_at: orig.scraped_at
  }
}];

const item = $json;
if (item._skip) return [{ json: item }];

// 1. Mentions score (0-100) — upvotes signal market interest
const upvotes = item.upvotes || 0;
const mentionsScore = Math.min(100, upvotes * 2);

// 2. Freshness score (0-100) — decays 10pts/day
const now = Date.now();
const scrapedAt = item.scraped_at ? new Date(item.scraped_at).getTime() : now;
const ageHours = (now - scrapedAt) / (1000 * 60 * 60);
const freshnessScore = Math.max(0, 100 - (ageHours / 24) * 10);

// 3. Market potential (0-100) — Claude's ai_score
const marketPotential = item.ai_score || 50;

// 4. LLM analysis quality (0-100) — completeness of structured output
let llmScore = 50;
if (item.competitive_edge) llmScore += 15;
if (item.why_now)          llmScore += 15;
if (item.market_gap)       llmScore += 10;
if (item.pain_points && item.pain_points.length > 1) llmScore += 10;
llmScore = Math.min(100, llmScore);

// Composite: score = (mentions*0.3) + (freshness*0.2) + (market*0.3) + (llm*0.2)
const rankingScore =
  (mentionsScore   * 0.3) +
  (freshnessScore  * 0.2) +
  (marketPotential * 0.3) +
  (llmScore        * 0.2);

// Pro Pick threshold: ~80 ≈ top 5% in normal distribution
const isProPick = rankingScore >= 80;

return [{
  json: {
    title:                   item.title,
    summary:                 item.summary,
    pain_points:             item.pain_points,
    target_customers:        item.target_customers,
    monetization_strategies: item.monetization_strategies,
    tech_stack_suggestions:  item.tech_stack_suggestions,
    tags:                    item.tags,
    competitive_edge:        item.competitive_edge,
    why_now:                 item.why_now,
    market_gap:              item.market_gap,
    ai_score:                item.ai_score,
    source_url:              item.source_url,
    source_platform:         item.source_platform,
    upvotes:                 item.upvotes,
    comment_count:           item.comment_count,
    ranking_score:           Math.round(rankingScore * 100) / 100,
    is_pro_pick:             isProPick
  }
}];
